/* eslint-disable @next/next/no-img-element */

import { cn } from "@/lib/utils";

const THEMED_LOGO_MAP: Record<string, { light: string; dark: string }> = {
  github: {
    light: "/logos/github-black.svg", // black icon for light mode
    dark: "/logos/github-white.svg",  // white icon for dark mode
  },
};

const LOGO_MAP: Record<string, string> = {
  "aws": "data:image/svg+xml;base64,",
  "azure": "data:image/svg+xml;base64,",
  "comfyui": "data:image/svg+xml;base64,",
  "github": "data:image/svg+xml;base64,",
  "google": "data:image/svg+xml;base64,",
  "google-cloud": "data:image/svg+xml;base64,",
  "huggingface": "data:image/svg+xml;base64,",
  "jupyter": "data:image/svg+xml;base64,",
  "nvidia": "data:image/svg+xml;base64,",
  "pytorch": "data:image/svg+xml;base64,",
  "runpod": "data:image/svg+xml;base64,",
  "tensorflow": "data:image/svg+xml;base64,",
  "ubuntu": "data:image/svg+xml;base64,",
  "vast": "data:image/svg+xml;base64,",
  "vllm": "data:image/svg+xml;base64,",
  "googlecloud": "data:image/svg+xml;base64,",
  "gcp": "data:image/svg+xml;base64,",
};

const LOGO_LABELS: Record<string, string> = {
  pytorch: "PyTorch",
  tensorflow: "TensorFlow",
  vllm: "vLLM",
  comfyui: "ComfyUI",
  jupyter: "Jupyter",
  ubuntu: "Ubuntu",
  aws: "AWS",
  azure: "Azure",
  google: "Google",
  "google-cloud": "Google Cloud",
  googlecloud: "Google Cloud",
  gcp: "Google Cloud",
  github: "GitHub",
  huggingface: "Hugging Face",
  nvidia: "NVIDIA",
  runpod: "RunPod",
  vast: "Vast.ai",
};

function normalizeProvider(provider: string): string {
  return provider.trim().toLowerCase().replace(/[_\s]+/g, "-");
}

function resolveLogo(provider: string): { key: string; src?: string; lightSrc?: string; darkSrc?: string } | null {
  const normalized = normalizeProvider(provider);
  const compact = normalized.replace(/-/g, "");
  const key = THEMED_LOGO_MAP[normalized]
    ? normalized
    : THEMED_LOGO_MAP[compact]
      ? compact
      : LOGO_MAP[normalized]
        ? normalized
        : LOGO_MAP[compact]
          ? compact
          : "";
  if (!key) return null;
  if (THEMED_LOGO_MAP[key]) {
    return {
      key,
      lightSrc: THEMED_LOGO_MAP[key].light,
      darkSrc: THEMED_LOGO_MAP[key].dark,
    };
  }
  return { key, src: LOGO_MAP[key] };
}

export function hasProviderLogo(provider: string): boolean {
  return Boolean(resolveLogo(provider));
}

interface ProviderLogoProps {
  provider: string;
  size?: number;
  framed?: boolean;
  className?: string;
  imageClassName?: string;
  label?: string;
}

export function ProviderLogo({
  provider,
  size = 20,
  framed = false,
  className,
  imageClassName,
  label,
}: ProviderLogoProps) {
  const resolved = resolveLogo(provider);
  if (!resolved) return null;

  // When framed, the outer container is larger and the icon sits centered inside
  const imageSize = size;
  const frameSize = framed ? Math.round(size * 1.6) : size;
  const alt = label ?? LOGO_LABELS[resolved.key] ?? provider;
  const image = resolved.lightSrc && resolved.darkSrc ? (
    <>
      <img
        src={resolved.lightSrc}
        alt={alt}
        width={imageSize}
        height={imageSize}
        loading="eager"
        decoding="sync"
        style={{ width: imageSize, height: imageSize }}
        className={cn(
          "block object-contain dark:hidden",
          !framed && className,
          imageClassName,
        )}
      />
      <img
        src={resolved.darkSrc}
        alt={alt}
        width={imageSize}
        height={imageSize}
        loading="eager"
        decoding="sync"
        style={{ width: imageSize, height: imageSize }}
        className={cn(
          "hidden object-contain dark:block",
          !framed && className,
          imageClassName,
        )}
      />
    </>
  ) : (
    <img
      src={resolved.src!}
      alt={alt}
      width={imageSize}
      height={imageSize}
      loading="eager"
      decoding="sync"
      style={{ width: imageSize, height: imageSize }}
      className={cn(
        "object-contain",
        !framed && className,
        imageClassName,
      )}
    />
  );

  if (!framed) return image;

  return (
    <span
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-2xl border border-border/70 bg-background/70 shadow-[inset_0_1px_0_rgba(255,255,255,0.04)]",
        className,
      )}
      style={{ width: frameSize, height: frameSize }}
    >
      {image}
    </span>
  );
}
